  ('aboriginal-c5fb3965-moex-00108', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '依憲法及增修條文規定，下列何者涉及共和國體制？', '["各民族一律平等", "總統由全體人民直接選舉產生", "人民身體之自由應予保障", "中華民國之外交，應本獨立自主之精神"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00109', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '依司法院大法官解釋，關於立法委員之選舉，下列敘述何者錯誤？', '["採政黨比例代表制，合憲", "政黨比例代表採百分之五之門檻規定，合憲", "單一選區兩票制採並立制，違憲", "政黨比例代表席次規定，合憲"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00110', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '有關憲法訴訟法所定憲法法庭判決，下列敘述何者錯誤？', '["憲法法庭得判決宣告法規範立即失效", "憲法法庭得判決宣告法規範定期失效", "憲法法庭得判決宣告法規範溯及失效", "憲法法庭判決宣告法律位階法規範定期失效，其所定期間不得逾3年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00111', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '我國大法官認為修憲有無界限？理由為何？', '["修憲無界限，因為新的民意不斷產生，後來的世代不應受到過去世代意志的永久拘束", "修憲無界限，因為憲法並未明文規定界限為何", "修憲有界限，因為憲法中具有本質之重要性之規定若可任意修改，會破壞憲法整體規範秩序", "修憲有界限，因為憲法有明文規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00112', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '依憲法規範及實務見解，下列何種權利的保障對象與其他選項不同？', '["言論自由", "秘密通訊自由", "服公職權", "人身自由"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00113', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '依歷年大法官解釋與憲法法庭判決，關於人身自由之憲法上保障，下列敘述何者正確？', '["肇事汽車駕駛人無法實施吐氣酒精濃度測試時，交通勤務警察為保留證據，即得將其強制移送醫療機構 進行血液採樣及測試，並未牴觸憲法保障之人身自由", "刑法規定，有犯罪習慣或因遊蕩懶惰成習而犯罪者，無論其犯罪行為型態與情節輕重，於刑之執行前， 均應入勞動場所強制工作，並未牴觸憲法上人身自由之保障", "行政執行之義務人，於行政執行處命其報告財產狀況，不為報告時，行政執行處即得聲請法院裁定管收 之規定，已逾越限制人身自由之必要程度", "憲法第8條第1項「……非經司法或警察機關依法定程序，不得逮捕拘禁」，其中「司法機關」不包括 檢察機關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00114', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '關於不當聯結禁止原則之敘述，下列何者錯誤？', '["可適用於行政處分附款之添加", "可適用於締結互負給付義務之行政契約", "係指行政行為不得考慮與其行政目的無正當合理關聯之因素", "行政程序法第一章總則已有明文規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00115', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '下列何者非屬行政罰法所定判斷主管機關管轄之基準？', '["違反行政法上義務之行為地", "違反行政法上義務之結果地", "行為人之居所", "主管機關所在地"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00116', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '依司法實務見解，關於明確性原則之敘述，下列何者錯誤？', '["包括法律明確性原則、授權明確性原則以及行政行為明確性原則", "並不適用於行政指導行為", "得依法律整體解釋之方法，推知立法者之授權內容及範圍，即無違法律授權明確性", "懲處處分之構成要件以抽象概念表示者，其意義須非難以理解，且為一般受規範者所得預見，並可經由 司法審查加以確認，始符法律明確性原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00117', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '關於行政法法源之敘述，下列何者錯誤？', '["緊急命令可以凍結法律和憲法的適用", "法規命令係指法律授權行政機關制定抽象而對外直接發生法律效力的規範", "行政規則係指行政機關基於內部處理行政事務之需要，無法律授權而依職權所為對內生效之抽象規定", "自治條例係指由地方立法機關制定通過之法規"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL)
